const items = $input.all();
if (items.length === 0) return [];
const out = [];
for (const item of items) {
  const j = item.json || {};
  // 1) Data
  let data = String(j.Data ?? j.data ?? j['Data'] ?? j['Data Lancamento'] ?? '').trim();
  if (!data) {
    for (const [k, v] of Object.entries(j)) {
      const s = String(v ?? '').trim();
      if (s.length === 10 && s[2] === '/' && s[5] === '/') {
        data = s;
        break;
      }
    }
  }
  // 2) Pessoa / descrição principal
  let pessoa = String(
    j.Pessoa ??
    j.pessoa ??
    j['Pessoa'] ??
    j.Histórico ??
    j.Historico ??
    j.Pagador ??
    j.Nome ??
    j.Descrição ??
    j.Descricao ??
    j.descricao ??
    ''
  ).trim();
  if (!pessoa) {
    for (const [k, v] of Object.entries(j)) {
      const s = String(v ?? '').trim();
      if (!s) continue;
      const lower = s.toLowerCase();
      if (s === data) continue;
      if (lower === 'data' || lower === 'tipo' || lower === 'saldo do dia') continue;
      if (lower === 'entradas' || lower === 'saidas' || lower === 'saldo') continue;
      if (lower.includes('disponivel credito')) continue;
      pessoa = s;
      break;
    }
  }
  // 3) Valores (entradas / saídas)
  let vCr = 0;
  let vDb = 0;
  for (const [key, value] of Object.entries(j)) {
    const keyLower = String(key).toLowerCase();
    if (keyLower === 'row_number') continue;
    if (keyLower.includes('saldo')) continue;
    let num = 0;
    if (typeof value === 'number') {
      num = value;
    } else {
      const s = String(value ?? '').trim();
      if (!s) continue;
      if (s.includes('R$')) continue;
      if (s.includes('/')) continue;
      const cleaned = s.split('.').join('').replace(',', '.');
      const parsed = parseFloat(cleaned);
      if (!Number.isFinite(parsed) || parsed === 0) continue;
      num = parsed;
    }
    if (num > 0) {
      if (!vCr) vCr = num;
    } else if (num < 0) {
      if (!vDb) vDb = Math.abs(num);
    }
  }
  // 4) Valor final e tipo
  let valor = 0;
  const baseValor = j.Valor ?? j.valor ?? j['Valor'];
  if (baseValor !== undefined && baseValor !== null) {
    const s = String(baseValor).trim();
    if (s) {
      const cleaned = s.split('.').join('').replace(',', '.');
      const parsed = parseFloat(cleaned);
      if (Number.isFinite(parsed) && parsed !== 0) {
        valor = parsed;
      }
    }
  }
  if (valor === 0 && (vCr > 0 || vDb > 0)) {
    valor = vCr || vDb;
    if (vCr > 0) j._tipo = 'entrada';
    else j._tipo = 'saida';
  }
  // 5) Descrição
  let descricao = String(j.Descrição ?? j.Descricao ?? j.descricao ?? '').trim();
  if (!descricao && pessoa) descricao = pessoa;
  // 6) Tipo (entrada/saida)
  let tipo = String(j._tipo ?? j.Tipo ?? j.tipo ?? j['Tipo'] ?? '').trim().toLowerCase();
  if (!tipo) {
    const tipoRaw = String(j.Tipo ?? j.tipo ?? j['Tipo'] ?? '').trim().toLowerCase();
    if (tipoRaw.includes('receb')) tipo = 'entrada';
    else if (tipoRaw.includes('venda')) tipo = 'entrada';
    else if (tipoRaw.includes('enviado')) tipo = 'saida';
    else if (tipoRaw.includes('pagamento')) tipo = 'saida';
  }
  if (tipo !== 'entrada') tipo = 'saida';
  // 7) Filtros finais
  if (!data || !pessoa || !valor) continue;
  if (data.indexOf('/') !== -1) {
    const p = data.split('/');
    if (p.length >= 3) data = p[2] + '-' + p[1] + '-' + p[0];
  } else if (data.indexOf('T') !== -1) {
    data = data.split('T')[0];
  }
  const id_unico = data + '-' + pessoa + '-' + valor;
  out.push({ json: { data, pessoa, valor, descricao, tipo, id_unico } });
}
return out;

const planilha = ($('Normalizar linhas').all() || []).map(i => i.json);
const existentesBrutas = ($('Transações já no Supabase').all() || []).map(i => i.json || {});
const makeKey = (r) => {
  const data = String(r.data || '').trim();
  const pessoa = String(r.pessoa || '').trim();
  const valor = Number(r.valor || 0);
  if (!data || !pessoa || !valor) return '';
  return data + '-' + pessoa + '-' + valor;
};
const existentes = existentesBrutas.map(makeKey).filter(Boolean);
const set = new Set(existentes);
const novos = planilha.filter(p => !set.has(makeKey(p)));
return novos.map(p => ({ json: p }));
